import React from 'react';
import { PieChart, Pie, Cell, ResponsiveContainer } from 'recharts';
import { SafetyStatus } from '../../types';

interface Props {
  statusData: SafetyStatus;
}

const STATUS_COLORS = {
  Safe: '#22c55e',     // Green
  Warning: '#eab308',  // Yellow
  Critical: '#ef4444', // Red
};

export const SafetyDonut: React.FC<Props> = ({ statusData }) => {
  // Data for the donut: [Current Value, Remaining to Max]
  // We normalize to a 100% scale for the donut look
  const percentage = Math.min(100, (statusData.value / (statusData.status === 'Critical' ? statusData.value : statusData.value * 2)) * 100);

  const data = [
    { name: 'Val', value: 1, color: STATUS_COLORS[statusData.status] },
    { name: 'Rest', value: 0, color: 'rgba(255,255,255,0.1)' } // Full circle filled
  ];

  // We actually want a ring showing status color entirely
  const ringData = [{ name: 'Status', value: 100, color: STATUS_COLORS[statusData.status] }];

  return (
    <div className="flex flex-row items-center bg-white/5 backdrop-blur-sm rounded-xl border border-white/10 p-3 h-full min-h-[100px] w-full">
      <div className="h-[80px] w-[80px] relative">
        <ResponsiveContainer width="100%" height="100%">
          <PieChart>
            <Pie
              data={ringData}
              cx="50%"
              cy="50%"
              innerRadius={28}
              outerRadius={35}
              startAngle={90}
              endAngle={-270}
              dataKey="value"
              stroke="none"
            >
              <Cell fill={ringData[0].color} />
            </Pie>
          </PieChart>
        </ResponsiveContainer>
        <div className="absolute inset-0 flex items-center justify-center">
          <span className="text-lg font-bold text-white shadow-black drop-shadow-md">
            {statusData.value.toFixed(0)}
          </span>
        </div>
      </div>

      <div className="ml-4 flex flex-col justify-center">
        <span className="text-gray-400 text-xs font-medium uppercase tracking-wider mb-1">
          {statusData.gas} Safety
        </span>
        <span 
          className="text-sm font-bold px-2 py-0.5 rounded-full inline-block text-center shadow-sm w-fit"
          style={{ 
            backgroundColor: `${STATUS_COLORS[statusData.status]}20`, // 20% opacity background
            color: STATUS_COLORS[statusData.status],
            border: `1px solid ${STATUS_COLORS[statusData.status]}50`
          }}
        >
          {statusData.status}
        </span>
      </div>
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { Header } from './components/Header';
import { KpiCard } from './components/KpiCard';
import { GasConcentrationPie } from './components/Charts/GasConcentrationPie';
import { GasLevelsBarChart } from './components/Charts/GasLevelsBarChart';
import { LiveReadingsTable } from './components/Charts/LiveReadingsTable';
import { HighestLevelsBarChart } from './components/Charts/HighestLevelsBarChart';
import { SafetyDonut } from './components/Charts/SafetyDonut';
import { generateReading, getSafetyStatus } from './services/dataService';
import { SensorReading, GasType, GAS_COLORS } from './types';

const App: React.FC = () => {
  const [data, setData] = useState<SensorReading>(generateReading());
  const [history, setHistory] = useState<SensorReading[]>([]);
  const [filter, setFilter] = useState<GasType>('All');

  // Simulation Loop
  useEffect(() => {
    // Initial data load
    const initialData = generateReading();
    setData(initialData);
    setHistory([initialData]);

    const interval = setInterval(() => {
      const newData = generateReading();
      setData(newData);
      setHistory(prev => {
        const newHistory = [...prev, newData];
        // Keep last 20 readings for charts
        return newHistory.slice(-20);
      });
    }, 2000);

    return () => clearInterval(interval);
  }, []);

  const safetyStatuses = getSafetyStatus(data);

  return (
    <div className="min-h-screen w-full bg-gradient-to-br from-indigo-950 via-[#2e1065] to-slate-900 p-4 lg:p-6 overflow-x-hidden font-sans text-white">
      <div className="max-w-[1600px] mx-auto flex flex-col gap-6">

        {/* HEADER */}
        <Header activeFilter={filter} onFilterChange={setFilter} />

        {/* TOP ROW: KPIs */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-4">
          <KpiCard title="NH₃ Level" value={data.nh3} unit="ppm" color={GAS_COLORS.nh3} />
          <KpiCard title="CO₂ Level" value={data.co2} unit="ppm" color={GAS_COLORS.co2} />
          <KpiCard title="NOx Level" value={data.nox} unit="ppb" color={GAS_COLORS.nox} />
          <KpiCard title="SO₂ Level" value={data.so2} unit="ppb" color={GAS_COLORS.so2} />
          <KpiCard title="System Temp" value={data.temperature} unit="°C" color={GAS_COLORS.env} />
        </div>

        {/* MIDDLE SECTION: MAIN CONTENT GRID */}
        {/* Using a layout that mimics the reference: 
            Col 1: Split (Pie top, Bar bottom)
            Col 2: Vertical Bar (Tall)
            Col 3: Table (Tall)
        */}
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-4 auto-rows-min">

          {/* LEFT COLUMN (Pie + Horizontal Bar) - Spans 3/12 cols */}
          <div className="lg:col-span-3 flex flex-col gap-4">
            <div className="h-[300px]">
              <GasConcentrationPie data={data} />
            </div>
            <div className="h-[250px] flex-1">
              <HighestLevelsBarChart data={data} />
            </div>
          </div>

          {/* CENTER COLUMN (Vertical Bar) - Spans 5/12 cols */}
          <div className="lg:col-span-5 h-[566px]">
            <GasLevelsBarChart history={history} />
          </div>

          {/* RIGHT COLUMN (Table) - Spans 4/12 cols */}
          <div className="lg:col-span-4 h-[566px]">
            <LiveReadingsTable history={history} />
          </div>

        </div>

        {/* BOTTOM ROW: SUMMARY DONUTS */}
        <div className="w-full bg-white/5 backdrop-blur-md rounded-2xl border border-white/10 p-4">
            <h3 className="text-white/70 text-sm font-semibold mb-3 ml-2 uppercase tracking-widest">System Safety Status Overview</h3>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-4">
              {safetyStatuses.map((status) => (
                <SafetyDonut key={status.gas} statusData={status} />
              ))}
            </div>
        </div>

      </div>
    </div>
  );
};

export default App;

