// TODO: Replace with your actual Firebase project configuration
const firebaseConfig = {
  apiKey: "YOUR_API_KEY",
  authDomain: "your-project-id.firebaseapp.com",
  databaseURL: "https://your-project-id-default-rtdb.firebaseio.com",
  projectId: "your-project-id",
  storageBucket: "your-project-id.appspot.com",
  messagingSenderId: "YOUR_SENDER_ID",
  appId: "YOUR_APP_ID"
};

// Initialize Firebase
const app = initializeApp(firebaseConfig);
const database = getDatabase(app);

const App: React.FC = () => {
  const [data, setData] = useState<SensorReading>({
    id: 'loading',
    timestamp: '--:--:--',
    nh3: 0,
    co2: 0,
    nox: 0,
    so2: 0,
    temperature: 0,
    humidity: 0,
    weight: 0
  });
  const [history, setHistory] = useState<SensorReading[]>([]);
  const [filter, setFilter] = useState<GasType>('All');
  const [connected, setConnected] = useState(false);

  useEffect(() => {
    // Reference to the sensor data path in your Firebase RTDB
    // Adjust 'sensor_readings/live' to match your DB structure
    const sensorRef = ref(database, 'readings');

    const unsubscribe = onValue(sensorRef, (snapshot) => {
      const val = snapshot.val();
      if (val) {
        setConnected(true);
        const now = new Date();
        const timestamp = now.toLocaleTimeString([], { hour12: false, hour: '2-digit', minute: '2-digit', second: '2-digit' });

        const newReading: SensorReading = {
          id: now.getTime().toString(),
          timestamp: timestamp,
          nh3: Number(val.nh3 ?? 0),
          co2: Number(val.co2 ?? 0),
          nox: Number(val.nox ?? 0),
          so2: Number(val.so2 ?? 0),
          temperature: Number(val.temperature ?? 0),
          humidity: Number(val.humidity ?? 0),
          weight: Number(val.weight ?? 0)
        };

        setData(newReading);
        setHistory(prev => {
          const newHistory = [...prev, newReading];
          return newHistory.slice(-20); // Maintain last 20 readings for visualization
        });
      }
    }, (error) => {
      console.error("Firebase Read Error:", error);
      setConnected(false);
    });

    return () => unsubscribe();
  }, []);

  const safetyStatuses = getSafetyStatus(data);

  return (
    <div className="min-h-screen w-full bg-gradient-to-br from-indigo-950 via-[#2e1065] to-slate-900 p-4 lg:p-6 overflow-x-hidden font-sans text-white">
      <div className="max-w-[1600px] mx-auto flex flex-col gap-6">

        {/* HEADER */}
        <div className="relative">
          <Header activeFilter={filter} onFilterChange={setFilter} />
          <div className="absolute top-0 right-0 mt-[-10px] flex items-center gap-2">
             <div className={`w-2 h-2 rounded-full ${connected ? 'bg-green-500 animate-pulse' : 'bg-red-500'}`}></div>
             <span className="text-[10px] uppercase font-bold text-white/40 tracking-tighter">
               {connected ? 'Live Sync' : 'Connecting...'}
             </span>
          </div>
        </div>

        {/* TOP ROW: KPIs */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-4">
          <KpiCard title="NH₃ Level" value={data.nh3} unit="ppm" color={GAS_COLORS.nh3} />
          <KpiCard title="CO₂ Level" value={data.co2} unit="ppm" color={GAS_COLORS.co2} />
          <KpiCard title="NOx Level" value={data.nox} unit="ppb" color={GAS_COLORS.nox} />
          <KpiCard title="SO₂ Level" value={data.so2} unit="ppb" color={GAS_COLORS.so2} />
          <KpiCard title="System Temp" value={data.temperature} unit="°C" color={GAS_COLORS.env} />
        </div>

        {/* MIDDLE SECTION: MAIN CONTENT GRID */}
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-4 auto-rows-min">

          {/* LEFT COLUMN (Pie + Horizontal Bar) */}
          <div className="lg:col-span-3 flex flex-col gap-4">
            <div className="h-[300px]">
              <GasConcentrationPie data={data} />
            </div>
            <div className="h-[250px] flex-1">
              <HighestLevelsBarChart data={data} />
            </div>
          </div>

          {/* CENTER COLUMN (Vertical Bar) */}
          <div className="lg:col-span-5 h-[566px]">
            <GasLevelsBarChart history={history} />
          </div>

          {/* RIGHT COLUMN (Table) */}
          <div className="lg:col-span-4 h-[566px]">
            <LiveReadingsTable history={history} />
          </div>

        </div>

        {/* BOTTOM ROW: SUMMARY DONUTS */}
        <div className="w-full bg-white/5 backdrop-blur-md rounded-2xl border border-white/10 p-4">
            <h3 className="text-white/70 text-sm font-semibold mb-3 ml-2 uppercase tracking-widest">System Safety Status Overview</h3>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-4">
              {safetyStatuses.map((status) => (
                <SafetyDonut key={status.gas} statusData={status} />
              ))}
            </div>
        </div>

      </div>
    </div>
  );
};

export default App;

export interface SensorReading {
  id: string;
  timestamp: string;
  nh3: number; // ppm
  co2: number; // ppm
  nox: number; // ppb
  so2: number; // ppb
  temperature: number; // Celsius
  humidity: number; // %
  weight: number; // kg (system load)
}

export type GasType = 'NH3' | 'CO2' | 'NOx' | 'SO2' | 'Env' | 'All';

export interface SafetyStatus {
  gas: string;
  value: number;
  status: 'Safe' | 'Warning' | 'Critical';
  color: string;
}

// New Interface for the IoT Hardware Status
export interface IoTSystemState {
  esp32_status: boolean;
  esp32_last_update: number; // Unix timestamp
  mq137: number;
  mq135: number;
  scd41: {
    co2: number;
    temperature: number;
    humidity: number;
  };
  loadcell: number;
  servo: boolean;
  uvc: boolean;
  battery: number;
}

export const GAS_COLORS = {
  nh3: '#06b6d4',
  co2: '#3b82f6',
  nox: '#f97316',
  so2: '#ef4444',
  env: '#14b8a6',
  text: '#ffffff',
  grid: 'rgba(255,255,255,0.1)',
};

import React from 'react';
