const StatusCard = ({ 
  label, 
  status, 
  subtext, 
  icon: Icon 
}: { 
  label: string; 
  status: 'ON' | 'OFF'; 
  subtext?: string; 
  icon: React.FC 
}) => {
  const isActive = status === 'ON';
  return (
    <div className={`relative flex items-center p-3 rounded-xl border transition-all duration-300 ${isActive ? 'bg-emerald-500/10 border-emerald-500/30' : 'bg-slate-800/50 border-white/5'}`}>
      <div className={`p-2 rounded-lg mr-3 ${isActive ? 'bg-emerald-500/20 text-emerald-400' : 'bg-slate-700 text-slate-400'}`}>
        <Icon />
      </div>
      <div className="flex-1">
        <div className="flex justify-between items-center mb-0.5">
          <h4 className="text-sm font-semibold text-gray-200">{label}</h4>
          <div className="flex items-center gap-1.5">
            <span className={`w-2 h-2 rounded-full shadow-[0_0_8px_currentColor] ${isActive ? 'bg-emerald-500 text-emerald-500' : 'bg-red-500 text-red-500'}`} />
            <span className={`text-xs font-bold ${isActive ? 'text-emerald-400' : 'text-red-400'}`}>{status}</span>
          </div>
        </div>
        {subtext && <p className="text-[10px] text-gray-400 uppercase tracking-wide">{subtext}</p>}
      </div>
    </div>
  );
};

export const IoTStatusGrid: React.FC<Props> = ({ systemData }) => {
  // Logic: ESP32 Heartbeat
  const currentTime = Math.floor(Date.now() / 1000);
  const lastUpdate = systemData.esp32_last_update;
  // Threshold 15 seconds. Note: systemData.esp32_status is a fallback boolean if timestamp logic fails or isn't used
  const isEspOnline = (currentTime - lastUpdate) <= 15 || systemData.esp32_status === true;

  // Logic: UV-C and LEDs
  const uvcActive = systemData.uvc;
  const redLedActive = uvcActive;   // Red ON if UV-C ON
  const greenLedActive = !uvcActive; // Green ON if UV-C OFF

  // Battery Color Logic
  const getBatteryColor = (level: number) => {
    if (level >= 60) return 'bg-green-500 shadow-[0_0_10px_rgba(34,197,94,0.5)]';
    if (level >= 30) return 'bg-yellow-500 shadow-[0_0_10px_rgba(234,179,8,0.5)]';
    return 'bg-red-500 shadow-[0_0_10px_rgba(239,68,68,0.5)]';
  };

  return (
    <div className="w-full bg-white/5 backdrop-blur-md rounded-2xl border border-white/10 p-5">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-5 gap-4">
        <h3 className="text-white font-bold text-lg uppercase tracking-widest border-l-4 border-blue-500 pl-3">
          Hardware Operational Status
        </h3>

        {/* Battery Widget */}
        <div className="flex items-center gap-3 bg-black/20 px-4 py-2 rounded-full border border-white/5">
          <span className="text-xs font-bold text-gray-400 uppercase">System Power</span>
          <div className="w-32 h-3 bg-gray-700 rounded-full overflow-hidden relative">
            <div 
              className={`h-full transition-all duration-500 ${getBatteryColor(systemData.battery)}`} 
              style={{ width: `${systemData.battery}%` }}
            />
          </div>
          <span className="text-sm font-mono font-bold text-white">{systemData.battery}%</span>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">

        {/* ESP32 Controller */}
        <StatusCard 
          label="ESP32 Controller" 
          status={isEspOnline ? 'ON' : 'OFF'} 
          subtext={isEspOnline ? `Last signal: ${(currentTime - lastUpdate)}s ago` : 'Signal Lost'}
          icon={Icons.Chip}
        />

        {/* Gas Sensors */}
        <StatusCard 
          label="MQ-137 (Ammonia)" 
          status={systemData.mq137 > 0 ? 'ON' : 'OFF'} 
          subtext={systemData.mq137 > 0 ? 'Reading Active' : 'No Data'}
          icon={Icons.Gas}
        />
        <StatusCard 
          label="MQ-135 (Air Quality)" 
          status={systemData.mq135 > 0 ? 'ON' : 'OFF'} 
          subtext={systemData.mq135 > 0 ? 'Reading Active' : 'No Data'}
          icon={Icons.Gas}
        />

        {/* Env Sensor */}
        <StatusCard 
          label="SCD41 Environment" 
          status={(systemData.scd41?.co2 > 0) ? 'ON' : 'OFF'} 
          subtext="CO₂, Temp, Hum"
          icon={Icons.Env}
        />

        {/* Actuators */}
        <StatusCard 
          label="Servo Motor" 
          status={systemData.servo ? 'ON' : 'OFF'} 
          subtext="Mechanism Status"
          icon={Icons.Servo}
        />
        <StatusCard 
          label="Load Cell" 
          status={systemData.loadcell !== undefined ? 'ON' : 'OFF'} 
          subtext="Weight Scale"
          icon={Icons.Weight}
        />

        {/* UV-C System & LED Logic */}
        <div className="lg:col-span-2 bg-slate-800/30 rounded-xl border border-white/5 p-3 flex flex-col sm:flex-row items-center justify-between gap-4">

          <div className="flex items-center gap-3 w-full sm:w-auto">
            <div className={`p-2 rounded-lg ${uvcActive ? 'bg-purple-500/20 text-purple-400' : 'bg-slate-700 text-slate-400'}`}>
              <Icons.Light />
            </div>
            <div>
              <h4 className="text-sm font-semibold text-gray-200">UV-C Light System</h4>
              <span className={`text-xs font-bold ${uvcActive ? 'text-purple-400' : 'text-gray-500'}`}>
                {uvcActive ? 'ACTIVE' : 'INACTIVE'}
              </span>
            </div>
          </div>

          <div className="flex items-center gap-6 bg-black/20 px-6 py-2 rounded-lg w-full sm:w-auto justify-center">
            {/* Red LED */}
            <div className="flex flex-col items-center gap-1">
              <div className={`w-4 h-4 rounded-full transition-all duration-300 ${redLedActive ? 'bg-red-500 shadow-[0_0_12px_#ef4444]' : 'bg-red-900/30'}`} />
              <span className="text-[10px] font-bold text-gray-400">RED</span>
            </div>

            <div className="h-8 w-px bg-white/10" />

            {/* Green LED */}
            <div className="flex flex-col items-center gap-1">
              <div className={`w-4 h-4 rounded-full transition-all duration-300 ${greenLedActive ? 'bg-green-500 shadow-[0_0_12px_#22c55e]' : 'bg-green-900/30'}`} />
              <span className="text-[10px] font-bold text-gray-400">GREEN</span>
            </div>

            <span className="text-[10px] text-gray-500 ml-2 uppercase tracking-tight">Status Indicators</span>
          </div>
        </div>

      </div>
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { initializeApp } from 'firebase/app';
import { getDatabase, ref, onValue } from 'firebase/database';
import { Header } from './components/Header';
import { KpiCard } from './components/KpiCard';
import { GasConcentrationPie } from './components/Charts/GasConcentrationPie';
import { GasLevelsBarChart } from './components/Charts/GasLevelsBarChart';
import { LiveReadingsTable } from './components/Charts/LiveReadingsTable';
import { HighestLevelsBarChart } from './components/Charts/HighestLevelsBarChart';
import { SafetyDonut } from './components/Charts/SafetyDonut';
import { IoTStatusGrid } from './components/IoTStatusGrid';
import { getSafetyStatus } from './services/dataService';
import { SensorReading, IoTSystemState, GasType, GAS_COLORS } from './types';

// TODO: Replace with your actual Firebase project configuration
const firebaseConfig = {
  apiKey: "YOUR_API_KEY",
  authDomain: "your-project-id.firebaseapp.com",
  databaseURL: "https://your-project-id-default-rtdb.firebaseio.com",
  projectId: "your-project-id",
  storageBucket: "your-project-id.appspot.com",
  messagingSenderId: "YOUR_SENDER_ID",
  appId: "YOUR_APP_ID"
};

// Initialize Firebase
const app = initializeApp(firebaseConfig);
const database = getDatabase(app);

const App: React.FC = () => {
  // Analytic Data State (for charts)
  const [data, setData] = useState<SensorReading>({
    id: 'loading',
    timestamp: '--:--:--',
    nh3: 0,
    co2: 0,
    nox: 0,
    so2: 0,
    temperature: 0,
    humidity: 0,
    weight: 0
  });

  // Hardware Status State
  const [systemState, setSystemState] = useState<IoTSystemState>({
    esp32_status: false,
    esp32_last_update: 0,
    mq137: 0,
    mq135: 0,
    scd41: { co2: 0, temperature: 0, humidity: 0 },
    loadcell: 0,
    servo: false,
    uvc: false,
    battery: 0
  });

  const [history, setHistory] = useState<SensorReading[]>([]);
  const [filter, setFilter] = useState<GasType>('All');
  const [connected, setConnected] = useState(false);

  useEffect(() => {
    // Connect to the root 'iot_system' node or adjust based on where ESP32 writes
    const iotRef = ref(database, 'iot_system');

    const unsubscribe = onValue(iotRef, (snapshot) => {
      const val = snapshot.val();
      if (val) {
        setConnected(true);
        const now = new Date();
        const timestamp = now.toLocaleTimeString([], { hour12: false, hour: '2-digit', minute: '2-digit', second: '2-digit' });

        // 1. Update System State (Raw Data)
        const newSystemState: IoTSystemState = {
          esp32_status: val.esp32_status ?? false,
          esp32_last_update: val.esp32_last_update ?? 0,
          mq137: Number(val.mq137 ?? 0),
          mq135: Number(val.mq135 ?? 0),
          scd41: {
            co2: Number(val.scd41?.co2 ?? 0),
            temperature: Number(val.scd41?.temperature ?? 0),
            humidity: Number(val.scd41?.humidity ?? 0)
          },
          loadcell: Number(val.loadcell ?? 0),
          servo: Boolean(val.servo),
          uvc: Boolean(val.uvc),
          battery: Number(val.battery ?? 0)
        };
        setSystemState(newSystemState);

        // 2. Map Raw Data to Analytics Model (SensorReading) for Charts
        // Logic: 
        // NH3 <- MQ137
        // CO2 <- SCD41.co2
        // NOx <- MQ135 (Assuming MQ135 proxies for general air quality/NOx here)
        // SO2 <- 0 (Not provided in new structure, keeping 0 to prevent crash)
        const newReading: SensorReading = {
          id: now.getTime().toString(),
          timestamp: timestamp,
          nh3: newSystemState.mq137,
          co2: newSystemState.scd41.co2,
          nox: newSystemState.mq135,
          so2: 0, 
          temperature: newSystemState.scd41.temperature,
          humidity: newSystemState.scd41.humidity,
          weight: newSystemState.loadcell
        };

        setData(newReading);
        setHistory(prev => {
          const newHistory = [...prev, newReading];
          return newHistory.slice(-20); // Maintain last 20 readings for visualization
        });
      }
    }, (error) => {
      console.error("Firebase Read Error:", error);
      setConnected(false);
    });

    return () => unsubscribe();
  }, []);

  const safetyStatuses = getSafetyStatus(data);

  return (
    <div className="min-h-screen w-full bg-gradient-to-br from-indigo-950 via-[#2e1065] to-slate-900 p-4 lg:p-6 overflow-x-hidden font-sans text-white">
      <div className="max-w-[1600px] mx-auto flex flex-col gap-6">

        {/* HEADER */}
        <div className="relative">
          <Header activeFilter={filter} onFilterChange={setFilter} />
          <div className="absolute top-0 right-0 mt-[-10px] flex items-center gap-2">
             <div className={`w-2 h-2 rounded-full ${connected ? 'bg-green-500 animate-pulse' : 'bg-red-500'}`}></div>
             <span className="text-[10px] uppercase font-bold text-white/40 tracking-tighter">
               {connected ? 'Live Sync' : 'Reconnecting...'}
             </span>
          </div>
        </div>

        {/* SECTION 1: IOT HARDWARE STATUS GRID */}
        <IoTStatusGrid systemData={systemState} />

        {/* SECTION 2: ANALYTIC KPIs */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-4">
          <KpiCard title="NH₃ Level" value={data.nh3} unit="ppm" color={GAS_COLORS.nh3} />
          <KpiCard title="CO₂ Level" value={data.co2} unit="ppm" color={GAS_COLORS.co2} />
          <KpiCard title="NOx/AQI Level" value={data.nox} unit="ppb" color={GAS_COLORS.nox} />
          <KpiCard title="Load Weight" value={data.weight} unit="kg" color={GAS_COLORS.so2} />
          <KpiCard title="System Temp" value={data.temperature} unit="°C" color={GAS_COLORS.env} />
        </div>

        {/* SECTION 3: MAIN ANALYTICS CHARTS */}
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-4 auto-rows-min">

          {/* LEFT COLUMN (Pie + Horizontal Bar) */}
          <div className="lg:col-span-3 flex flex-col gap-4">
            <div className="h-[300px]">
              <GasConcentrationPie data={data} />
            </div>
            <div className="h-[250px] flex-1">
              <HighestLevelsBarChart data={data} />
            </div>
          </div>

          {/* CENTER COLUMN (Vertical Bar) */}
          <div className="lg:col-span-5 h-[566px]">
            <GasLevelsBarChart history={history} />
          </div>

          {/* RIGHT COLUMN (Table) */}
          <div className="lg:col-span-4 h-[566px]">
            <LiveReadingsTable history={history} />
          </div>

        </div>

        {/* SECTION 4: SAFETY SUMMARY */}
