export const IoTStatusGrid: React.FC<Props> = ({ systemData }) => {
  // Logic: ESP32 Heartbeat
  const currentTime = Math.floor(Date.now() / 1000);
  const lastUpdate = systemData.esp32_last_update;
  const isEspOnline = (currentTime - lastUpdate) <= 15 || systemData.esp32_status === true;

  // Logic: UV-C and LEDs
  const uvcActive = systemData.uvc;
  const redLedActive = uvcActive;   
  const greenLedActive = !uvcActive; 

  // Battery Segment Logic
  const segments = 10;
  const filledSegments = Math.ceil((systemData.battery / 100) * segments);

  const getSegmentColor = (index: number) => {
    if (index >= filledSegments) return 'bg-gray-800'; // Empty
    if (systemData.battery < 30) return 'bg-red-500 shadow-[0_0_5px_#ef4444]';
    if (systemData.battery < 60) return 'bg-yellow-500 shadow-[0_0_5px_#eab308]';
    return 'bg-emerald-500 shadow-[0_0_5px_#10b981]';
  };

  return (
    <div className="w-full bg-[#0f172a]/60 backdrop-blur-xl rounded-3xl border border-white/5 p-6 shadow-2xl">
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center mb-8 gap-6 border-b border-white/5 pb-6">
        <div className="flex items-center gap-3">
            <div className={`w-3 h-3 rounded-full ${isEspOnline ? 'bg-green-500 shadow-[0_0_10px_#22c55e]' : 'bg-red-500 shadow-[0_0_10px_#ef4444]'} animate-pulse`} />
            <h3 className="text-white font-black text-xl uppercase tracking-widest">
            System Hardware
            </h3>
        </div>

        {/* Futuristic Battery Widget */}
        <div className="flex items-center gap-4 bg-black/40 px-5 py-2.5 rounded-full border border-white/5 shadow-inner">
          <Icons.Battery />
          <div className="flex gap-1">
            {Array.from({ length: segments }).map((_, i) => (
              <div 
                key={i} 
                className={`w-2 h-4 rounded-sm transition-all duration-300 ${getSegmentColor(i)}`}
              />
            ))}
          </div>
          <span className="text-sm font-mono font-bold text-white ml-2 border-l border-white/10 pl-3">
            {systemData.battery}%
          </span>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-4 gap-4">

        {/* ESP32 Controller */}
        <StatusCard 
          label="ESP32 MCU" 
          status={isEspOnline ? 'ON' : 'OFF'} 
          subtext={isEspOnline ? `Heartbeat: Active` : 'Signal Lost'}
          icon={Icons.Chip}
        />

        {/* Gas Sensors */}
        <StatusCard 
          label="MQ-137 Array" 
          status={systemData.mq137 > 0 ? 'ON' : 'OFF'} 
          subtext={systemData.mq137 > 0 ? 'Data Streaming' : 'No Signal'}
          icon={Icons.Gas}
        />
        <StatusCard 
          label="MQ-135 Array" 
          status={systemData.mq135 > 0 ? 'ON' : 'OFF'} 
          subtext={systemData.mq135 > 0 ? 'Data Streaming' : 'No Signal'}
          icon={Icons.Gas}
        />

        {/* Env Sensor */}
        <StatusCard 
          label="SCD41 Module" 
          status={(systemData.scd41?.co2 > 0) ? 'ON' : 'OFF'} 
          subtext="Env Monitoring"
          icon={Icons.Env}
        />

        {/* Actuators */}
        <StatusCard 
          label="Servo Mech" 
          status={systemData.servo ? 'ON' : 'OFF'} 
          subtext="Position Lock"
          icon={Icons.Servo}
        />
        <StatusCard 
          label="Load Cell" 
          status={systemData.loadcell !== undefined ? 'ON' : 'OFF'} 
          subtext="Calibrated"
          icon={Icons.Weight}
        />

        {/* Custom UV-C Control Panel */}
        <div className="xl:col-span-2 bg-gradient-to-r from-slate-900 to-slate-800 rounded-xl border border-white/5 p-4 flex flex-row items-center justify-between gap-6 relative overflow-hidden group">
          {/* Background Glow */}
          {uvcActive && (
             <div className="absolute inset-0 bg-purple-500/10 mix-blend-overlay pointer-events-none" />
          )}

          <div className="flex items-center gap-4 z-10">
            <div className={`p-3 rounded-xl transition-all duration-500 ${uvcActive ? 'bg-purple-600 shadow-[0_0_20px_#9333ea] text-white' : 'bg-gray-800 text-gray-500'}`}>
              <Icons.Light />
            </div>
            <div>
              <h4 className="text-sm font-bold text-gray-100 uppercase tracking-wider">UV-C Sterilization</h4>
              <span className={`text-[10px] font-bold px-2 py-0.5 rounded border mt-1 inline-block ${uvcActive ? 'text-purple-300 border-purple-500/30 bg-purple-500/10' : 'text-gray-500 border-gray-700'}`}>
                {uvcActive ? 'SEQUENCE ACTIVE' : 'STANDBY'}
              </span>
            </div>
          </div>

          {/* Realistic LEDs */}
          <div className="flex gap-6 z-10 bg-black/40 px-6 py-3 rounded-lg border border-white/5">
            <div className="flex flex-col items-center gap-2">
                <div className={`w-3 h-3 rounded-full transition-all duration-200 ${redLedActive ? 'bg-red-500 shadow-[0_0_15px_#ef4444] scale-110' : 'bg-red-950 border border-red-900/30'}`} />
                <span className="text-[9px] font-bold text-gray-500">BUSY</span>
            </div>
            <div className="flex flex-col items-center gap-2">
                <div className={`w-3 h-3 rounded-full transition-all duration-200 ${greenLedActive ? 'bg-emerald-500 shadow-[0_0_15px_#10b981] scale-110' : 'bg-emerald-950 border border-emerald-900/30'}`} />
                <span className="text-[9px] font-bold text-gray-500">READY</span>
            </div>
          </div>
        </div>

      </div>
    </div>
