        });
      }
    };

    const handleError = (error: any) => {
      console.error("Firebase Read Error:", error);
      setConnected(false);
    };

    iotRef.on('value', handleData, handleError);

    return () => { iotRef.off('value', handleData); };
  }, []);

  const safetyStatuses = getSafetyStatus(data);

