export const IoTStatusGrid: React.FC<Props> = ({ systemData, onReset }) => {
  // Logic: ESP32 Heartbeat
  const currentTime = Math.floor(Date.now() / 1000);
  const lastUpdate = systemData.esp32_last_update;
  const isEspOnline = (currentTime - lastUpdate) <= 15 || systemData.esp32_status === true;

  // Logic: UV-C and LEDs
  const uvcActive = systemData.uvc;
  const redLedActive = uvcActive;   
  const greenLedActive = !uvcActive; 

  // Battery Segment Logic
  const segments = 10;
  const filledSegments = Math.ceil((systemData.battery / 100) * segments);

  const getSegmentColor = (index: number) => {
    if (index >= filledSegments) return 'bg-gray-800/50'; // Empty
    if (systemData.battery < 30) return 'bg-red-500 shadow-[0_0_8px_#ef4444]';
    if (systemData.battery < 60) return 'bg-yellow-500 shadow-[0_0_8px_#eab308]';
    return 'bg-emerald-500 shadow-[0_0_8px_#10b981]';
  };

  return (
    <div className="w-full bg-[#1e293b]/40 backdrop-blur-xl rounded-3xl border border-white/5 p-6 shadow-2xl relative overflow-hidden">
      {/* Decorative Grid Background */}
      <div className="absolute inset-0 bg-[linear-gradient(rgba(255,255,255,0.02)_1px,transparent_1px),linear-gradient(90deg,rgba(255,255,255,0.02)_1px,transparent_1px)] bg-[size:24px_24px] pointer-events-none" />

      <div className="relative z-10 flex flex-col lg:flex-row justify-between items-start lg:items-center mb-8 gap-6 border-b border-white/5 pb-6">
        <div className="flex items-center gap-3">
            <div className={`w-3 h-3 rounded-full ${isEspOnline ? 'bg-green-500 shadow-[0_0_15px_#22c55e]' : 'bg-red-500 shadow-[0_0_15px_#ef4444]'} animate-pulse`} />
            <h3 className="text-white font-black text-xl uppercase tracking-[0.15em] drop-shadow-md">
            System Hardware
            </h3>
        </div>

        {/* Right Side Controls */}
        <div className="flex flex-col sm:flex-row items-start sm:items-center gap-4">

          {/* Reset Button */}
          {onReset && (
            <button 
              onClick={onReset}
              className="group flex items-center gap-2 px-4 py-2 bg-red-500/10 hover:bg-red-500/20 border border-red-500/20 hover:border-red-500/50 rounded-xl transition-all duration-300 hover:shadow-[0_0_15px_rgba(239,68,68,0.2)] active:scale-95 active:bg-red-500/30"
            >
              <svg className="w-4 h-4 text-red-500 group-hover:rotate-180 transition-transform duration-700" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
              </svg>
              <span className="text-[10px] font-black text-red-400 uppercase tracking-widest group-hover:text-red-300">
                Reboot System
              </span>
            </button>
          )}

          {/* Futuristic Battery Widget */}
          <div className="flex items-center gap-4 bg-black/40 px-6 py-3 rounded-full border border-white/10 shadow-[inset_0_2px_10px_rgba(0,0,0,0.5)]">
            <Icons.Battery />
            <div className="flex gap-1.5">
              {Array.from({ length: segments }).map((_, i) => (
                <div 
                  key={i} 
                  className={`w-2 h-5 rounded-[2px] transition-all duration-300 ${getSegmentColor(i)}`}
                />
              ))}
            </div>
            <span className="text-sm font-mono font-bold text-white ml-2 border-l border-white/10 pl-4 tracking-wider">
              {systemData.battery}%
            </span>
          </div>

        </div>
      </div>

      <div className="relative z-10 grid grid-cols-1 md:grid-cols-2 xl:grid-cols-4 gap-4">

        {/* ESP32 Controller */}
        <StatusCard 
          label="ESP32 MCU" 
          status={isEspOnline ? 'ON' : 'OFF'} 
          subtext={isEspOnline ? `Heartbeat: Active` : 'Signal Lost'}
          icon={Icons.Chip}
        />

        {/* Gas Sensors */}
        <StatusCard 
          label="MQ-137 Array" 
          status={systemData.mq137 > 0 ? 'ON' : 'OFF'} 
          subtext={systemData.mq137 > 0 ? 'Data Streaming' : 'No Signal'}
          icon={Icons.Gas}
        />
        <StatusCard 
          label="MQ-135 Array" 
          status={systemData.mq135 > 0 ? 'ON' : 'OFF'} 
          subtext={systemData.mq135 > 0 ? 'Data Streaming' : 'No Signal'}
          icon={Icons.Gas}
        />

        {/* Env Sensor */}
        <StatusCard 
          label="SCD41 Module" 
          status={(systemData.scd41?.co2 > 0) ? 'ON' : 'OFF'} 
          subtext="Env Monitoring"
          icon={Icons.Env}
        />

        {/* Actuators */}
        <StatusCard 
          label="Servo Mech" 
          status={systemData.servo ? 'ON' : 'OFF'} 
          subtext="Position Lock"
          icon={Icons.Servo}
        />
        <StatusCard 
          label="Load Cell" 
          status={systemData.loadcell !== undefined ? 'ON' : 'OFF'} 
          subtext="Calibrated"
          icon={Icons.Weight}
        />

        {/* Custom UV-C Control Panel */}
        <div className="xl:col-span-2 bg-gradient-to-r from-slate-900/80 to-slate-800/80 rounded-xl border border-white/10 p-4 flex flex-row items-center justify-between gap-6 relative overflow-hidden group hover:border-purple-500/30 transition-colors duration-500">
          {/* Background Glow */}
          {uvcActive && (
             <div className="absolute inset-0 bg-purple-500/10 mix-blend-overlay pointer-events-none animate-pulse" />
          )}
          <div className="absolute inset-0 bg-[linear-gradient(rgba(255,255,255,0.03)_1px,transparent_1px)] bg-[size:10px_10px] pointer-events-none opacity-50" />

          <div className="flex items-center gap-5 z-10">
            <div className={`p-4 rounded-xl transition-all duration-500 ${uvcActive ? 'bg-purple-600 shadow-[0_0_25px_#9333ea] text-white scale-105' : 'bg-gray-800 text-gray-500'}`}>
              <Icons.Light />
            </div>
            <div>
              <h4 className="text-sm font-bold text-gray-100 uppercase tracking-wider">UV-C Sterilization</h4>
              <span className={`text-[10px] font-bold px-3 py-1 rounded-md border mt-1.5 inline-block tracking-widest ${uvcActive ? 'text-purple-300 border-purple-500/30 bg-purple-500/10 shadow-[0_0_10px_rgba(168,85,247,0.2)]' : 'text-gray-500 border-gray-700'}`}>
                {uvcActive ? 'SEQUENCE ACTIVE' : 'STANDBY'}
              </span>
            </div>
          </div>

          {/* Realistic LEDs */}
          <div className="flex gap-6 z-10 bg-black/50 px-8 py-3 rounded-lg border border-white/10 shadow-[inset_0_2px_8px_rgba(0,0,0,0.6)]">
            <div className="flex flex-col items-center gap-2">
                <div className={`w-3.5 h-3.5 rounded-full transition-all duration-200 ${redLedActive ? 'bg-red-500 shadow-[0_0_20px_#ef4444] scale-110' : 'bg-red-950 border border-red-900/30 opacity-50'}`} />
                <span className={`text-[9px] font-bold ${redLedActive ? 'text-red-400' : 'text-gray-600'}`}>BUSY</span>
            </div>
            <div className="w-px h-8 bg-white/10" />
            <div className="flex flex-col items-center gap-2">
                <div className={`w-3.5 h-3.5 rounded-full transition-all duration-200 ${greenLedActive ? 'bg-emerald-500 shadow-[0_0_20px_#10b981] scale-110' : 'bg-emerald-950 border border-emerald-900/30 opacity-50'}`} />
                <span className={`text-[9px] font-bold ${greenLedActive ? 'text-emerald-400' : 'text-gray-600'}`}>READY</span>
            </div>
          </div>
        </div>

      </div>
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { initializeApp } from 'firebase/app';
import { getDatabase, ref, onValue, set } from 'firebase/database';
import { Header } from './components/Header';
import { KpiCard } from './components/KpiCard';
import { GasConcentrationPie } from './components/Charts/GasConcentrationPie';
import { GasLevelsBarChart } from './components/Charts/GasLevelsBarChart';
import { LiveReadingsTable } from './components/Charts/LiveReadingsTable';
import { HighestLevelsBarChart } from './components/Charts/HighestLevelsBarChart';
import { SafetyDonut } from './components/Charts/SafetyDonut';
import { IoTStatusGrid } from './components/IoTStatusGrid';
import { getSafetyStatus } from './services/dataService';
import { SensorReading, IoTSystemState, GasType, GAS_COLORS } from './types';

// Firebase Project Configuration
const firebaseConfig = {
  apiKey: "AIzaSyDrhKHstFwZmBmz4Qd_QZWeCONJjOny9O4",
  authDomain: "solanirad-analytics-dashboard.firebaseapp.com",
  databaseURL: "https://solanirad-analytics-dashboard-default-rtdb.asia-southeast1.firebasedatabase.app/",
  projectId: "solanirad-analytics-dashboard",
  storageBucket: "solanirad-analytics-dashboard.firebasestorage.app",
  messagingSenderId: "915597225709",
  appId: "1:915597225709:web:94ceafd1cb5423830d26e4",
  measurementId: "G-77DDBWPJ5S"
};

// Initialize Firebase
const app = initializeApp(firebaseConfig);
const database = getDatabase(app);

const App: React.FC = () => {
  // Analytic Data State (for charts)
  const [data, setData] = useState<SensorReading>({
    id: 'loading',
    timestamp: '--:--:--',
    nh3: 0,
    co2: 0,
    nox: 0,
    so2: 0,
    temperature: 0,
    humidity: 0,
    weight: 0
  });

  // Hardware Status State
  const [systemState, setSystemState] = useState<IoTSystemState>({
    esp32_status: false,
    esp32_last_update: 0,
    mq137: 0,
    mq135: 0,
    scd41: { co2: 0, temperature: 0, humidity: 0 },
    loadcell: 0,
    servo: false,
    uvc: false,
    battery: 0
  });

  const [history, setHistory] = useState<SensorReading[]>([]);
  const [filter, setFilter] = useState<GasType>('All');
  const [connected, setConnected] = useState(false);

  useEffect(() => {
    // Connect to the root 'iot_system' node
    const iotRef = ref(database, 'iot_system');

    const unsubscribe = onValue(iotRef, (snapshot) => {
      const val = snapshot.val();
      if (val) {
        setConnected(true);
        const now = new Date();
        const timestamp = now.toLocaleTimeString([], { hour12: false, hour: '2-digit', minute: '2-digit', second: '2-digit' });

        // 1. Update System State (Raw Data)
        const newSystemState: IoTSystemState = {
          esp32_status: val.esp32_status ?? false,
          esp32_last_update: val.esp32_last_update ?? 0,
          mq137: Number(val.mq137 ?? 0),
          mq135: Number(val.mq135 ?? 0),
          scd41: {
            co2: Number(val.scd41?.co2 ?? 0),
            temperature: Number(val.scd41?.temperature ?? 0),
            humidity: Number(val.scd41?.humidity ?? 0)
          },
          loadcell: Number(val.loadcell ?? 0),
          servo: Boolean(val.servo),
          uvc: Boolean(val.uvc),
          battery: Number(val.battery ?? 0)
        };
        setSystemState(newSystemState);

        // 2. Map Raw Data to Analytics Model (SensorReading) for Charts
        const newReading: SensorReading = {
          id: now.getTime().toString(),
          timestamp: timestamp,
          nh3: newSystemState.mq137,
          co2: newSystemState.scd41.co2,
          nox: newSystemState.mq135,
          so2: 0, 
          temperature: newSystemState.scd41.temperature,
          humidity: newSystemState.scd41.humidity,
          weight: newSystemState.loadcell
        };

        setData(newReading);
        setHistory(prev => {
          const newHistory = [...prev, newReading];
          return newHistory.slice(-20); // Maintain last 20 readings for visualization
        });
      }
    }, (error) => {
      console.error("Firebase Read Error:", error);
      setConnected(false);
    });

    return () => unsubscribe();
  }, []);

  const safetyStatuses = getSafetyStatus(data);

  // Function to handle ESP32 Reset Link
  const handleReset = () => {
    const confirmed = window.confirm(
      "CONFIRM REBOOT: Initiate ESP32 System Reset Sequence?"
    );

    if (confirmed) {
      // Method 1: Write to Firebase (Remote Trigger)
      // The ESP32 should listen to changes on 'iot_system/command'
      set(ref(database, 'iot_system/command'), 'RESET')
        .then(() => {
           console.log("Reset command synced to cloud.");
        })
        .catch(err => console.error("Cloud sync failed:", err));

      // Method 2: Open Direct Link (Local AP Mode) in New Tab
      window.open('http://192.168.4.1/reset', '_blank');
    }
  };

  return (
    <div className="min-h-screen w-full bg-gradient-to-br from-indigo-950 via-[#2e1065] to-slate-900 p-4 lg:p-6 overflow-x-hidden font-sans text-white">
      <div className="max-w-[1600px] mx-auto flex flex-col gap-6">

        {/* HEADER */}
        <div className="relative">
          <Header activeFilter={filter} onFilterChange={setFilter} />
          <div className="absolute top-0 right-0 mt-[-10px] flex items-center gap-2">
             <div className={`w-2 h-2 rounded-full ${connected ? 'bg-green-500 animate-pulse' : 'bg-red-500'}`}></div>
             <span className="text-[10px] uppercase font-bold text-white/40 tracking-tighter">
               {connected ? 'Live Sync' : 'Reconnecting...'}
             </span>
          </div>
        </div>

        {/* SECTION 1: IOT HARDWARE STATUS GRID */}
        <IoTStatusGrid systemData={systemState} onReset={handleReset} />

        {/* SECTION 2: ANALYTIC KPIs */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-4">
          <KpiCard title="NH₃ Level" subtitle="Ammonia" value={data.nh3} unit="ppm" color={GAS_COLORS.nh3} />
          <KpiCard title="CO₂ Level" subtitle="Carbon Dioxide" value={data.co2} unit="ppm" color={GAS_COLORS.co2} />
          <KpiCard title="NOx/AQI Level" subtitle="Nitrogen Oxides" value={data.nox} unit="ppb" color={GAS_COLORS.nox} />
          <KpiCard title="Load Weight" subtitle="Total Load" value={data.weight} unit="kg" color={GAS_COLORS.so2} />
          <KpiCard title="System Temp" subtitle="Internal" value={data.temperature} unit="°C" color={GAS_COLORS.env} />
        </div>

        {/* SECTION 3: MAIN ANALYTICS CHARTS */}
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-4 auto-rows-min">

          {/* LEFT COLUMN (Pie + Horizontal Bar) */}
          <div className="lg:col-span-3 flex flex-col gap-4">
            <div className="h-[300px]">
              <GasConcentrationPie data={data} />
            </div>
            <div className="h-[250px] flex-1">
              <HighestLevelsBarChart data={data} />
            </div>
          </div>

          {/* CENTER COLUMN (Vertical Bar) */}
          <div className="lg:col-span-5 h-[566px]">
            <GasLevelsBarChart history={history} />
          </div>

          {/* RIGHT COLUMN (Table) */}
          <div className="lg:col-span-4 h-[566px]">
            <LiveReadingsTable history={history} />
          </div>

        </div>

        {/* SECTION 4: SAFETY SUMMARY */}
        <div className="w-full bg-white/5 backdrop-blur-md rounded-2xl border border-white/10 p-4">
            <h3 className="text-white/70 text-sm font-semibold mb-3 ml-2 uppercase tracking-widest">System Safety Status Overview</h3>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-4">
              {safetyStatuses.map((status) => (
                <SafetyDonut key={status.gas} statusData={status} />
              ))}
            </div>
        </div>

      </div>
    </div>
  );
};

export default App;

