Here is the complete **Arduino (ESP32)** code designed to connect specifically to your SolaniRad dashboard.

It includes the logic to **simulate sensor data** (so you can see the dashboard animate immediately without real sensors attached), handles the **Battery Logic** we just discussed, and implements the **Remote Reboot** functionality.

### Prerequisites

1.  Open Arduino IDE.
2.  Go to **Sketch** -> **Include Library** -> **Manage Libraries...**
3.  Search for and install: **Firebase ESP32 Client** by *Mobizt*.
4.  Select your ESP32 board in Tools.

### The ESP32 Code

```cpp
#include <WiFi.h>
#include <FirebaseESP32.h>
#include <time.h> // For timestamp generation

// =========================================================
// 1. WIFI CREDENTIALS (UPDATE THESE)
// =========================================================
#define WIFI_SSID "YOUR_WIFI_NAME"
#define WIFI_PASSWORD "YOUR_WIFI_PASSWORD"

// =========================================================
// 2. FIREBASE CONFIGURATION (MATCHING YOUR APP.TSX)
// =========================================================
#define FIREBASE_HOST "solanirad-analytics-dashboard-default-rtdb.asia-southeast1.firebasedatabase.app"
#define FIREBASE_AUTH "AIzaSyDrhKHstFwZmBmz4Qd_QZWeCONJjOny9O4"

// Firebase Objects
FirebaseData fbData;
FirebaseAuth auth;
FirebaseConfig config;
FirebaseJson json;

// =========================================================
// 3. SYSTEM VARIABLES & SIMULATION STATE
// =========================================================
unsigned long lastSendTime = 0;
const int sendInterval = 2000; // Send data every 2 seconds

// Simulation variables (To make the dashboard look alive)
float sim_mq137 = 25.0; // NH3
float sim_mq135 = 50.0; // NOx
float sim_co2 = 400.0;
float sim_temp = 24.0;
float sim_humid = 45.0;
float sim_weight = 120.0;
float sim_battery = 100.0; // Start at 100%

// Logic to drain battery for demo
unsigned long lastBatteryDrain = 0;

void setup() {
  Serial.begin(115200);

  // 1. Connect to Wi-Fi
  WiFi.begin(WIFI_SSID, WIFI_PASSWORD);
  Serial.print("Connecting to Wi-Fi");
  while (WiFi.status() != WL_CONNECTED) {
    Serial.print(".");
    delay(300);
  }
  Serial.println();
  Serial.print("Connected with IP: ");
  Serial.println(WiFi.localIP());

  // 2. Sync Time (Required for dashboard 'Live Sync' indicator)
  configTime(0, 0, "pool.ntp.org", "time.nist.gov");
  Serial.print("Waiting for NTP time sync: ");
  time_t now = time(nullptr);
  while (now < 8 * 3600 * 2) {
    delay(500);
    Serial.print(".");
    now = time(nullptr);
  }
  Serial.println("Time Synced!");

  // 3. Initialize Firebase
  config.api_key = FIREBASE_AUTH;
  config.database_url = FIREBASE_HOST;

  // Optimize for connection stability
  Firebase.reconnectWiFi(true);
  fbData.setResponseSize(1024);

  Firebase.begin(&config, &auth);
}

void loop() {
  // Check for Remote Reboot Command constantly
  checkRebootCommand();

  // Send Sensor Data periodically
  if (millis() - lastSendTime > sendInterval) {
    lastSendTime = millis();

    // A. Update Simulation Data (Replace this with real sensor reads later)
    updateSimulatedSensors();

    // B. Get Current Unix Timestamp
    time_t now = time(nullptr);

    // C. Prepare JSON Object matching 'IoTSystemState' in types.ts
    json.clear();
    json.set("esp32_status", true);
    json.set("esp32_last_update", (int)now);

    // Gas Sensors
    json.set("mq137", sim_mq137); // NH3
    json.set("mq135", sim_mq135); // NOx

    // SCD41 (Env)
    json.set("scd41/co2", sim_co2);
    json.set("scd41/temperature", sim_temp);
    json.set("scd41/humidity", sim_humid);

    // Hardware
    json.set("loadcell", sim_weight);
    json.set("battery", (int)sim_battery);

    // Status Flags (Example logic: Servo active if Weight > 125)
    bool servoState = (sim_weight > 125.0);
    bool uvcState = (sim_mq137 > 35.0); // Turn on UVC if NH3 is high

    json.set("servo", servoState);
    json.set("uvc", uvcState);

    // D. Send to Firebase
    Serial.printf("Updating Firebase... Bat: %.0f%%\n", sim_battery);

    if (Firebase.updateNode(fbData, "/iot_system", json)) {
      // Success
    } else {
      Serial.println(fbData.errorReason());
    }
  }
}

// =========================================================
// HELPER: REMOTE REBOOT LOGIC
// =========================================================
void checkRebootCommand() {
  if (Firebase.ready()) {
    // Read only the specific reboot path to save bandwidth
    if (Firebase.getBool(fbData, "/iot_system/control/reboot")) {
      if (fbData.dataType() == "boolean") {
        bool shouldReboot = fbData.boolData();

        if (shouldReboot) {
          Serial.println("!!! REBOOT COMMAND RECEIVED !!!");

          // 1. Acknowledge by setting flag back to false
          // This prevents infinite reboot loop
          Firebase.setBool(fbData, "/iot_system/control/reboot", false);

          // 2. Wait a moment to ensure write finishes
          delay(1000);

          // 3. Restart ESP32
          ESP.restart();
        }
      }
    }
  }
}

// =========================================================
// HELPER: SIMULATE SENSOR VALUES (Random Walk)
// =========================================================
void updateSimulatedSensors() {
  // Helper to drift values naturally
  auto drift = [](float &val, float min, float max, float step) {
    val += ((float)random(-100, 101) / 100.0) * step;
    if (val < min) val = min;
    if (val > max) val = max;
  };

  drift(sim_mq137, 10.0, 50.0, 2.0);    // NH3
  drift(sim_mq135, 20.0, 150.0, 5.0);   // NOx
  drift(sim_co2, 350.0, 1200.0, 15.0);  // CO2
  drift(sim_temp, 20.0, 35.0, 0.5);     // Temp
  drift(sim_humid, 40.0, 80.0, 1.0);    // Humidity
  drift(sim_weight, 118.0, 128.0, 0.5); // Weight

  // Battery Drain Simulation (Drops 1% every 1 second for demo purposes)
  // This helps you test the Color Logic (Green -> Yellow -> Orange -> Red)
  if (millis() - lastBatteryDrain > 1000) {
    lastBatteryDrain = millis();
    sim_battery -= 1; 
    if (sim_battery < 5) sim_battery = 100; // Reset to 100 if dead
  }
}
```

### How to test this:

1.  **WiFi**: Change `WIFI_SSID` and `WIFI_PASSWORD` at the top of the file.
2.  **Upload**: Flash this code to your ESP32.
3.  **Watch Serial Monitor**: Set baud rate to `115200`. You should see it connect.
4.  **Watch Dashboard**:
    *   The "Reconnecting..." indicator in the top right should turn into a green pulsing **"LIVE SYNC"** dot.
    *   The values in the cards and charts will start moving.
    *   **Battery Test**: Watch the battery bar. It will drain rapidly (1% per second). You will see it change from **Green** -> **Yellow** -> **Amber** -> **Red** -> **Critical Flashing** as it drains, verifying your React logic.
    *   **Reboot Test**: Click the Red "Reboot System" button on the dashboard. Watch the Serial Monitor on the Arduino IDE; it will say "REBOOT COMMAND RECEIVED", resets the flag, and the ESP32 will actually restart.

