        <div className={`w-full h-[500px] transition-opacity duration-500 ${isEspOnline ? 'opacity-100' : 'opacity-50 grayscale'}`}>
             <LiveReadingsTable history={history} />
        </div>

      </div>
    </div>
  );
};

